// Vuelos con fechas y ventanas de check-in
const flights = [
  { label: 'Madrid → Shanghai', date: '2026-03-12', ref: 'NKX5J4', airline: 'Hainan Airlines', checkinHours: 24, url: 'https://www.hainanairlines.com/builder/GoPage?type=manage' },
  { label: 'Shanghai → Taipei', date: '2026-03-16', ref: '1433808606921603', airline: 'Spring Airlines', checkinHours: 24, url: 'https://flights.ch.spring.com/OrderSearch' },
  { label: 'Taipei → Bangkok', date: '2026-03-19', ref: 'IHI3HH', airline: 'Thai AirAsia', checkinHours: 336, url: 'https://www.airasia.com/check-in/en/gb?bookingId=IHI3HH' },
  { label: 'Bangkok → Krabi', date: '2026-03-20', ref: '4Z44R2', airline: 'Thai VietJet', checkinHours: 24, url: 'https://www.vietjetair.com/en/manage-booking' },
  { label: 'Krabi → Bangkok', date: '2026-03-29', ref: 'NGUN2K', airline: 'Thai AirAsia', checkinHours: 336, url: 'https://www.airasia.com/check-in/en/gb?bookingId=NGUN2K' },
  { label: 'Bangkok → Xi\'an', date: '2026-03-30', ref: 'OHSEFR', airline: 'Thai Lion Air', checkinHours: 24, url: 'https://www.lionairthai.com/en/manage-booking' },
  { label: 'Beijing → Madrid', date: '2026-04-07', ref: 'NKZ9RH / JJMFL', airline: 'China Southern + Iberia', checkinHours: 24, url: 'https://www.iberia.com/es/gestionar-reserva/' }
];

const now = new Date();
const alerts = [];

for (const f of flights) {
  const flightDate = new Date(f.date + 'T00:00:00');
  const hoursUntilFlight = (flightDate - now) / (1000 * 60 * 60);
  const hoursUntilCheckin = hoursUntilFlight - f.checkinHours;

  // Alert when check-in opens (within 12h window) or 24h before flight
  if (hoursUntilCheckin <= 12 && hoursUntilCheckin > -12) {
    alerts.push({ ...f, type: 'checkin_open', hoursUntilFlight: Math.round(hoursUntilFlight) });
  } else if (hoursUntilFlight <= 24 && hoursUntilFlight > 0) {
    alerts.push({ ...f, type: 'flight_tomorrow', hoursUntilFlight: Math.round(hoursUntilFlight) });
  }
}

return alerts.map(a => ({ json: a }));
